import { useEffect, useState } from "react";
import { useParams, useNavigate } from "react-router-dom";
import axios from "../api/axios";

export default function VerifyBooking() {
    const { bookingId } = useParams();
    const navigate = useNavigate();
    const [booking, setBooking] = useState(null);
    const [loading, setLoading] = useState(true);
    const [error, setError] = useState("");

    useEffect(() => {
        const fetchBooking = async () => {
            try {
                const res = await axios.get(`/bookings/${bookingId}`);
                setBooking(res.data);
                setLoading(false);
            } catch (err) {
                console.error("Verification failed", err);
                if (err.response && (err.response.status === 401 || err.response.status === 403)) {
                    setError("Unauthorized: Please Login as Admin or Owner");
                } else {
                    setError("Booking Not Found or Invalid");
                }
                setLoading(false);
            }
        };
        fetchBooking();
    }, [bookingId]);

    if (loading) return <div style={{ textAlign: "center", marginTop: "50px" }}>Verifying Booking...</div>;

    if (error) {
        return (
            <div style={{ textAlign: "center", marginTop: "50px", color: "#c62828" }}>
                <h2>❌ Verification Failed</h2>
                <p>{error}</p>
                <button onClick={() => navigate("/login")} style={{ padding: "10px 20px", marginTop: "20px", cursor: "pointer" }}>Login to Verify</button>
            </div>
        );
    }

    const isValid = booking.status === "Active" || booking.status === "Completed";
    const isPaid = booking.paymentStatus === "Paid";

    return (
        <div style={{ display: "flex", justifyContent: "center", padding: "40px", background: "#f5f5f5", minHeight: "80vh" }}>
            <div style={{ background: "white", borderRadius: "15px", boxShadow: "0 10px 30px rgba(0,0,0,0.1)", maxWidth: "500px", width: "100%", overflow: "hidden" }}>

                {/* Status Header */}
                <div style={{
                    background: isValid && isPaid ? "#2ecc71" : "#e74c3c",
                    padding: "30px",
                    textAlign: "center",
                    color: "white"
                }}>
                    <h1 style={{ margin: 0, fontSize: "2.5rem" }}>{isValid && isPaid ? "✔ VALID" : "❌ INVALID"}</h1>
                    <p style={{ margin: "5px 0 0", opacity: 0.9 }}>
                        {isPaid ? "Payment Verified" : "Payment Pending/Failed"}
                    </p>
                </div>

                {/* Details */}
                <div style={{ padding: "30px" }}>
                    <h3 style={{ borderBottom: "2px solid #eee", paddingBottom: "10px", color: "#34495e" }}>📋 Booking Details</h3>

                    <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: "20px", marginBottom: "20px" }}>
                        <div>
                            <div style={labelStyle}>Vehicle Number</div>
                            <div style={valueStyle}>{booking.vehicleNumber}</div>
                        </div>
                        <div>
                            <div style={labelStyle}>Vehicle Type</div>
                            <div style={valueStyle}>{booking.vehicleType}</div>
                        </div>
                        <div>
                            <div style={labelStyle}>Parking Lot</div>
                            <div style={valueStyle}>{booking.slotId?.parkingLotId?.name || "Unknown"}</div>
                        </div>
                        <div>
                            <div style={labelStyle}>Slot Number</div>
                            <div style={valueStyle}>{booking.slotId?.slotNumber}</div>
                        </div>
                    </div>

                    <div style={{ background: "#f9f9f9", padding: "15px", borderRadius: "10px", marginBottom: "20px" }}>
                        <div style={labelStyle}>Time Range</div>
                        <div style={{ color: "#2c3e50", fontWeight: "bold" }}>
                            {new Date(booking.startTime).toLocaleString()} <br />
                            ⬇ <br />
                            {new Date(booking.endTime).toLocaleString()}
                        </div>
                    </div>

                    <h3 style={{ borderBottom: "2px solid #eee", paddingBottom: "10px", color: "#34495e" }}>👤 User Details</h3>
                    <div style={{ display: "flex", gap: "10px", alignItems: "center" }}>
                        <div style={{ background: "#3498db", color: "white", width: "40px", height: "40px", borderRadius: "50%", display: "flex", alignItems: "center", justifyContent: "center", fontWeight: "bold" }}>
                            {booking.userId?.name?.charAt(0) || "U"}
                        </div>
                        <div>
                            <div style={{ fontWeight: "bold", color: "#2c3e50" }}>{booking.userId?.name}</div>
                            <div style={{ fontSize: "0.9em", color: "#7f8c8d" }}>{booking.userId?.email}</div>
                        </div>
                    </div>

                </div>

                {/* Footer Action */}
                <div style={{ background: "#f8f9fa", padding: "20px", textAlign: "center" }}>
                    <button onClick={() => navigate("/")} style={{ background: "transparent", border: "1px solid #ccc", padding: "10px 20px", borderRadius: "5px", cursor: "pointer" }}>Back to Home</button>
                </div>
            </div>
        </div>
    );
}

const labelStyle = { color: "#95a5a6", fontSize: "0.85em", textTransform: "uppercase", marginBottom: "5px" };
const valueStyle = { color: "#2c3e50", fontWeight: "bold", fontSize: "1.1em" };
